#include <bits/stdc++.h>using namespace std;typedef long long ll;ll mod = 1e9 + 7;void bfs_complement(ll start, ll cnt, vector<unordered_set<ll>> &adj, vector<ll> &vis, set<ll> &unvisited){    queue<ll> q;    q.push(start);    vis[start] = cnt;    unvisited.erase(start);    while (!q.empty()){        ll node = q.front();        q.pop();        vector<ll> to_visit;        for (auto it = unvisited.begin(); it != unvisited.end();){            if (adj[node].find(*it) == adj[node].end()){                to_visit.push_back(*it);                it = unvisited.erase(it);            }            else{                it++;            }        }        for (ll v : to_visit){            vis[v] = cnt;            q.push(v);        }    }}int main(){    ll n, m;    cin >> n >> m;    vector<unordered_set<ll>> adj(n);    for (int i = 0; i < m; i++){        ll a, b;        cin >> a >> b;        a--;        b--;        adj[a].insert(b);        adj[b].insert(a);    }    vector<ll> vis(n, 0);    set<ll> unvisited;    for (int i = 0; i < n; i++)unvisited.insert(i);    ll cnt = 1;    for (int i = 0; i < n; i++){        if (vis[i] == 0){            bfs_complement(i, cnt, adj, vis, unvisited);            cnt++;        }    }    unordered_set<ll> s;    for (int i = 0; i < n; i++){        s.insert(vis[i]);    }    cout << (s.size() - 1) << endl;}